<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<style>
        :root{--primary:#1B4D3E;--primary-light:#2A7A5F;--primary-dark:#0F2E25;--accent:#F59E0B;--accent-light:#FCD34D;--surface:#FAFAF8;--surface-alt:#F0EFEB;--card:#FFFFFF;--text:#1A1A1A;--text-secondary:#555555;--text-muted:#888888;--border:#E5E5E0;--success:#059669;--info:#0EA5E9;--danger:#DC2626;--radius:12px;--radius-lg:20px;--shadow-sm:0 1px 3px rgba(0,0,0,0.06);--shadow-md:0 4px 16px rgba(0,0,0,0.08);--shadow-lg:0 8px 32px rgba(0,0,0,0.1);--font-body:'DM Sans',sans-serif;--font-mono:'Space Mono',monospace}
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
        html{scroll-behavior:smooth}
        body{font-family:var(--font-body);background:var(--surface);color:var(--text);line-height:1.65;-webkit-font-smoothing:antialiased}
        .toc-nav{background:var(--primary-dark);position:sticky;top:0;z-index:100;overflow-x:auto;white-space:nowrap;-webkit-overflow-scrolling:touch;box-shadow:0 2px 8px rgba(0,0,0,0.15)}
        .toc-nav-inner{max-width:1200px;margin:0 auto;padding:0 20px;display:flex}
        .toc-nav a{color:rgba(255,255,255,0.75);text-decoration:none;font-size:13px;font-weight:500;padding:12px 16px;transition:all 0.2s;border-bottom:2px solid transparent;display:inline-block}
        .toc-nav a:hover,.toc-nav a.active{color:#fff;border-bottom-color:var(--accent)}
        .breadcrumb{max-width:1200px;margin:0 auto;padding:16px 20px 0;font-size:13px;color:var(--text-muted)}
        .breadcrumb a{color:var(--primary-light);text-decoration:none}
        .breadcrumb a:hover{text-decoration:underline}
        .breadcrumb span{margin:0 6px}
        .hero{max-width:1200px;margin:0 auto;padding:32px 20px 24px}
        .hero-meta{display:flex;flex-wrap:wrap;align-items:center;gap:12px;margin-bottom:16px}
        .badge-updated{background:var(--primary);color:#fff;font-size:12px;font-weight:600;padding:4px 12px;border-radius:20px;letter-spacing:0.3px}
        .author-byline{font-size:13px;color:var(--text-secondary)}
        .author-byline strong{color:var(--primary);font-weight:600}
        .hero h1{font-size:clamp(24px,5vw,40px);font-weight:700;color:var(--primary-dark);line-height:1.2;margin-bottom:16px}
        .hero h1 span{color:var(--accent)}
        .tldr{background:var(--card);border-left:4px solid var(--accent);border-radius:0 var(--radius) var(--radius) 0;padding:20px 24px;margin:0 20px 32px;box-shadow:var(--shadow-sm)}
        @media(min-width:1240px){.tldr{margin-left:auto;margin-right:auto;max-width:1200px}}
        .tldr-label{font-family:var(--font-mono);font-size:12px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:1px;margin-bottom:8px}
        .tldr p{font-size:15px;color:var(--text-secondary);line-height:1.7}
        .main-layout{max-width:1200px;margin:0 auto;padding:0 20px 40px;display:grid;grid-template-columns:1fr;gap:32px}
        @media(min-width:900px){.main-layout{grid-template-columns:1fr 320px;gap:40px}}
        .content-col,.sidebar-col{min-width:0}
        .calc-card{background:var(--card);border-radius:var(--radius-lg);box-shadow:var(--shadow-lg);padding:32px;margin-bottom:40px;border:1px solid var(--border)}
        .calc-card h2{font-size:22px;font-weight:700;color:var(--primary-dark);margin-bottom:20px}
        .tool-mode-toggle{display:flex;background:var(--surface-alt);border-radius:var(--radius);padding:4px;gap:4px;margin-bottom:28px}
        .mode-btn{flex:1;padding:10px 16px;border:none;border-radius:8px;font-family:var(--font-body);font-size:14px;font-weight:600;color:var(--text-muted);background:transparent;cursor:pointer;transition:all 0.25s;text-align:center;-webkit-tap-highlight-color:transparent}
        .mode-btn *{pointer-events:none}
        .mode-btn.active{background:var(--card);color:var(--primary);box-shadow:var(--shadow-sm)}
        .search-row{display:grid;grid-template-columns:1fr auto;gap:12px;margin-bottom:16px}
        @media(max-width:500px){.search-row{grid-template-columns:1fr}}
        .search-wrap{position:relative}
        .search-wrap svg{position:absolute;left:14px;top:50%;transform:translateY(-50%);color:var(--text-muted);pointer-events:none}
        .search-input{width:100%;padding:12px 16px 12px 42px;border:2px solid var(--border);border-radius:var(--radius);font-family:var(--font-body);font-size:15px;color:var(--text);background:var(--surface);outline:none;transition:border-color 0.2s}
        .search-input:focus{border-color:var(--primary)}
        .search-input::placeholder{color:var(--text-muted)}
        .filter-select{padding:12px 16px;border:2px solid var(--border);border-radius:var(--radius);font-family:var(--font-body);font-size:14px;color:var(--text);background:var(--surface);outline:none;cursor:pointer;min-width:160px;transition:border-color 0.2s}
        .filter-select:focus{border-color:var(--primary)}
        .result-meta{font-size:13px;color:var(--text-muted);margin-bottom:12px}
        .result-meta strong{color:var(--text)}
        .table-wrap{overflow-x:auto;border-radius:var(--radius);border:1px solid var(--border)}
        .tds-table{width:100%;border-collapse:collapse;font-size:13.5px}
        .tds-table thead th{background:var(--primary);color:rgba(255,255,255,0.9);padding:12px 14px;text-align:left;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.3px;white-space:nowrap}
        .tds-table thead th:first-child{border-radius:var(--radius) 0 0 0}
        .tds-table thead th:last-child{border-radius:0 var(--radius) 0 0}
        .tds-table tbody td{padding:11px 14px;border-bottom:1px solid var(--border);color:var(--text-secondary);vertical-align:top}
        .tds-table tbody tr:last-child td{border-bottom:none}
        .tds-table tbody tr:nth-child(even){background:var(--surface)}
        .tds-table tbody tr:hover{background:#F0F7F4}
        .tds-table tbody tr.row-hidden{display:none}
        .section-tag{font-family:var(--font-mono);font-size:11.5px;font-weight:700;background:var(--primary-dark);color:var(--accent-light);padding:2px 7px;border-radius:5px;white-space:nowrap}
        .payment-name{font-weight:600;color:var(--text);font-size:13px;display:block;margin-bottom:2px}
        .payment-note{font-size:11.5px;color:var(--text-muted);line-height:1.5}
        .rate-badge{display:inline-block;padding:2px 9px;border-radius:20px;font-family:var(--font-mono);font-size:12px;font-weight:700;white-space:nowrap}
        .rb-high{background:#FEE2E2;color:#DC2626}
        .rb-mid{background:#FEF3C7;color:#B45309}
        .rb-low{background:#D1FAE5;color:#059669}
        .rb-slab{background:#EDE9FE;color:#7C3AED}
        .rb-nil{background:#F3F4F6;color:#6B7280}
        .rb-nopan{background:#FEE2E2;color:#DC2626;font-size:11.5px}
        .threshold-val{font-family:var(--font-mono);font-size:12px;color:var(--text);font-weight:700}
        .deductor-text{font-size:12px;color:var(--text-muted)}
        .no-results{text-align:center;padding:48px 20px;color:var(--text-muted)}
        .no-results p{margin-top:12px;font-size:14px}
        .calc-row{display:grid;grid-template-columns:1fr;gap:20px;margin-bottom:20px}
        @media(min-width:560px){.calc-row{grid-template-columns:1fr 1fr}}
        .form-group label{display:block;font-size:13px;font-weight:600;color:var(--text-secondary);margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px}
        .form-group select,.form-group input{width:100%;padding:12px 16px;border:2px solid var(--border);border-radius:var(--radius);font-family:var(--font-body);font-size:16px;color:var(--text);background:var(--surface);transition:border-color 0.2s;outline:none}
        .form-group select:focus,.form-group input:focus{border-color:var(--primary)}
        .form-group input[type="number"]{font-family:var(--font-mono);font-size:18px;font-weight:700}
        .toggle-group{display:flex;background:var(--surface-alt);border-radius:var(--radius);padding:4px;gap:4px}
        .toggle-btn{flex:1;padding:10px 12px;border:none;border-radius:8px;font-family:var(--font-body);font-size:13px;font-weight:600;color:var(--text-muted);background:transparent;cursor:pointer;transition:all 0.25s;text-align:center;-webkit-tap-highlight-color:transparent}
        .toggle-btn *{pointer-events:none}
        .toggle-btn.active{background:var(--card);color:var(--primary);box-shadow:var(--shadow-sm)}
        .btn-calculate{width:100%;padding:14px;background:var(--primary);color:#fff;border:none;border-radius:var(--radius);font-family:var(--font-body);font-size:16px;font-weight:700;cursor:pointer;transition:background 0.2s,transform 0.1s;margin-top:8px}
        .btn-calculate:hover{background:var(--primary-light)}
        .btn-calculate:active{transform:scale(0.98)}
        .result-section{margin-top:28px;display:none}
        .result-section.visible{display:block}
        .result-divider{height:1px;background:var(--border);margin-bottom:24px}
        .result-grid{display:grid;grid-template-columns:1fr;gap:12px}
        @media(min-width:480px){.result-grid{grid-template-columns:1fr 1fr}}
        .result-card{background:var(--surface);border-radius:var(--radius);padding:16px 20px;border:1px solid var(--border)}
        .result-card.highlight{background:var(--primary);border-color:var(--primary);grid-column:1/-1}
        .result-card.highlight .result-label,.result-card.highlight .result-value{color:#fff}
        .result-card.danger-card{background:#FEF2F2;border-color:#FECACA;grid-column:1/-1}
        .result-card.danger-card .result-label{color:#B91C1C}
        .result-card.danger-card .result-value{color:#7F1D1D}
        .result-label{font-size:12px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px}
        .result-value{font-family:var(--font-mono);font-size:22px;font-weight:700;color:var(--primary-dark)}
        .result-breakdown{margin-top:16px;background:var(--surface-alt);border-radius:var(--radius);padding:16px 20px}
        .breakdown-row{display:flex;justify-content:space-between;align-items:center;padding:7px 0;font-size:14px}
        .breakdown-row:not(:last-child){border-bottom:1px dashed var(--border)}
        .breakdown-label{color:var(--text-secondary)}
        .breakdown-value{font-family:var(--font-mono);font-weight:700;color:var(--text)}
        .btn-reset{display:inline-flex;align-items:center;gap:6px;margin-top:16px;padding:8px 16px;border:1px solid var(--border);border-radius:8px;background:var(--card);color:var(--text-muted);font-family:var(--font-body);font-size:13px;font-weight:500;cursor:pointer;transition:all 0.2s}
        .btn-reset:hover{border-color:var(--danger);color:var(--danger)}
        .content-section{background:var(--card);border-radius:var(--radius-lg);box-shadow:var(--shadow-sm);padding:32px;margin-bottom:32px;border:1px solid var(--border)}
        .content-section h2{font-size:24px;font-weight:700;color:var(--primary-dark);margin-bottom:16px;line-height:1.3}
        .content-section h3{font-size:18px;font-weight:700;color:var(--primary-dark);margin:20px 0 10px}
        .content-section p{font-size:15px;color:var(--text-secondary);margin-bottom:14px;line-height:1.75}
        .content-section a{color:var(--primary-light);text-decoration:underline;text-underline-offset:2px}
        .content-section a:hover{color:var(--primary)}
        .data-table{width:100%;border-collapse:collapse;margin:16px 0;font-size:14px}
        .data-table thead th{background:var(--primary);color:#fff;padding:12px 16px;text-align:left;font-weight:600;font-size:13px;text-transform:uppercase;letter-spacing:0.3px}
        .data-table thead th:first-child{border-radius:var(--radius) 0 0 0}
        .data-table thead th:last-child{border-radius:0 var(--radius) 0 0}
        .data-table tbody td{padding:11px 16px;border-bottom:1px solid var(--border);color:var(--text-secondary)}
        .data-table tbody tr:nth-child(even){background:var(--surface)}
        .data-table tbody tr:hover{background:var(--surface-alt)}
        .data-table td strong{font-family:var(--font-mono);color:var(--text)}
        .callout{background:#EFF6FF;border-left:4px solid var(--info);border-radius:0 var(--radius) var(--radius) 0;padding:16px 20px;margin:16px 0}
        .callout p{color:#1E40AF;margin-bottom:0;font-size:14px}
        .callout strong{color:#1E3A8A}
        .callout.warn{background:#FFFBEB;border-left-color:var(--accent)}
        .callout.warn p{color:#92400E}
        .callout.warn strong{color:#78350F}
        .formula-box{background:var(--primary-dark);color:#fff;border-radius:var(--radius);padding:20px 24px;margin:16px 0;font-family:var(--font-mono);font-size:13px;line-height:1.9;overflow-x:auto}
        .formula-box .label{color:var(--accent-light);font-weight:700}
        .quick-ref-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin:16px 0}
        .qr-card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:14px}
        .qr-card .qr-section{font-family:var(--font-mono);font-size:11px;font-weight:700;color:var(--primary);text-transform:uppercase;margin-bottom:4px}
        .qr-card .qr-rate{font-family:var(--font-mono);font-size:20px;font-weight:700;color:var(--primary-dark)}
        .qr-card .qr-label{font-size:12px;color:var(--text-muted);margin-top:2px}
        .faq-item{background:var(--surface);border-radius:var(--radius);margin-bottom:10px;border:1px solid var(--border);overflow:hidden;transition:box-shadow 0.2s}
        .faq-item:hover{box-shadow:var(--shadow-sm)}
        .faq-question{display:flex;justify-content:space-between;align-items:center;width:100%;padding:16px 20px;border:none;background:none;font-family:var(--font-body);font-size:15px;font-weight:600;color:var(--text);cursor:pointer;text-align:left;line-height:1.4;gap:12px;-webkit-tap-highlight-color:transparent}
        .faq-question *{pointer-events:none}
        .faq-icon{flex-shrink:0;width:24px;height:24px;border-radius:50%;background:var(--primary);color:#fff;display:flex;align-items:center;justify-content:center;font-size:16px;transition:transform 0.3s}
        .faq-item.open .faq-icon{transform:rotate(45deg)}
        .faq-answer{max-height:0;overflow:hidden;transition:max-height 0.35s ease}
        .faq-item.open .faq-answer{max-height:500px}
        .faq-answer-inner{padding:0 20px 16px;font-size:14px;color:var(--text-secondary);line-height:1.75}
