    {section:"196D",payment:"Income of FIIs from securities",threshold:"Nil",rateInd:"20%",rateOther:"20%",noPAN:"20%",deductor:"Any person",category:"nri",note:""},
    {section:"206AA",payment:"Higher TDS \u2014 No PAN furnished (overriding section)",threshold:"N/A",rateInd:"20%",rateOther:"20%",noPAN:"20%",deductor:"All deductors",category:"other",note:"Overrides all lower rates. Inoperative PAN = no PAN."}
];

function rateClass(r){if(!r||r==='N/A'||r==='Varies')return'rb-nil';if(r==='Slab')return'rb-slab';const n=parseFloat(r);if(isNaN(n))return'rb-nil';if(n>=20)return'rb-high';if(n>=10)return'rb-mid';return'rb-low';}

function buildTable(){
    const tbody=document.getElementById('tableBody');
    tbody.innerHTML='';
    TDS_DATA.forEach(row=>{
        const tr=document.createElement('tr');
        tr.dataset.category=row.category;
        tr.dataset.search=(row.section+' '+row.payment+' '+row.category+' '+(row.note||'')).toLowerCase();
        const dual=row.rateOther!==row.rateInd&&row.rateOther!=='N/A';
        tr.innerHTML=`<td><span class="section-tag">Sec. ${row.section}</span></td>
        <td><span class="payment-name">${row.payment}</span>${row.note?`<span class="payment-note">${row.note}</span>`:''}</td>
        <td><span class="threshold-val">${row.threshold}</span></td>
        <td><span class="rate-badge ${rateClass(row.rateInd)}">${row.rateInd}</span>${dual?`<br><small style="font-size:11px;color:#888;margin-top:2px;display:block">Company: <span class="rate-badge ${rateClass(row.rateOther)}" style="font-size:11px;padding:1px 6px">${row.rateOther}</span></small>`:''}</td>
        <td><span class="rate-badge rb-nopan">${row.noPAN}</span></td>
        <td><span class="deductor-text">${row.deductor}</span></td>`;
        tbody.appendChild(tr);
    });
    updateMeta();
    populateDrop();
}

function filterTable(){
    const q=(document.getElementById('searchInput').value||'').toLowerCase().trim();
    const cat=document.getElementById('categoryFilter').value;
    let v=0;
    document.querySelectorAll('#tableBody tr').forEach(tr=>{
        const ok=(!q||tr.dataset.search.includes(q))&&(!cat||tr.dataset.category===cat);
        tr.classList.toggle('row-hidden',!ok);
        if(ok)v++;
    });
    document.getElementById('noResults').style.display=v===0?'block':'none';
    updateMeta(v);
}

function updateMeta(n){
    const total=TDS_DATA.length;
    document.getElementById('resultMeta').innerHTML=`Showing <strong>${n!==undefined?n:total}</strong> of ${total} TDS sections`;
}

function populateDrop(){
    const sel=document.getElementById('calcSection');
    TDS_DATA.filter(d=>!['Slab','Varies'].includes(d.rateInd)&&d.section!=='206AA').forEach(d=>{
        const opt=document.createElement('option');
        opt.value=d.section;
        opt.textContent=`Sec. ${d.section} \u2014 ${d.payment.length>58?d.payment.substring(0,58)+'\u2026':d.payment}`;
        sel.appendChild(opt);
    });
}

function jumpToSection(sec){
    // Switch to Rate Finder mode
    var finderBtn = document.querySelectorAll('.mode-btn')[0];
    switchMode('finder', finderBtn);
    // Set search and filter
    document.getElementById('searchInput').value = sec;
    document.getElementById('categoryFilter').value = '';
    filterTable();
    // Scroll to tool section
    setTimeout(function(){
        document.getElementById('tool').scrollIntoView({behavior:'smooth'});
    }, 100);
}

function switchMode(mode,btn){
    document.querySelectorAll('.mode-btn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById('rateFinder').style.display=mode==='finder'?'block':'none';
    document.getElementById('calcPane').style.display=mode==='calc'?'block':'none';
    if(mode==='calc')document.getElementById('calcPane').scrollIntoView({behavior:'smooth',block:'start'});
}

let panStatus='yes';
function setPAN(btn){
    panStatus=btn.dataset.value;
    btn.parentElement.querySelectorAll('.toggle-btn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
}

function fmtI(n){return'\u20B9'+n.toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2});}

function getSurcharge(k){return{individual_below50:0,individual_50to1cr:0.10,individual_above1cr:0.15,domestic_company:0.07,foreign_company:0.02,firm:0.12}[k]||0;}

function calculateTDS(){
    const secId=document.getElementById('calcSection').value;
    const amount=parseFloat(document.getElementById('calcAmount').value);
    const payeeType=document.getElementById('calcPayeeType').value;
    const surchargeKey=document.getElementById('calcSurcharge').value;
    if(!secId){alert('Please select a TDS section.');return;}
    if(!amount||amount<=0){alert('Please enter a valid amount greater than zero.');return;}
    const row=TDS_DATA.find(d=>d.section===secId);
    if(!row)return;
    const rateStr=payeeType==='individual'?row.rateInd:row.rateOther;
    let baseRate=parseFloat(rateStr)/100;
    if(isNaN(baseRate)){alert('This section does not have a calculable flat rate. Please consult a CA for slab-based or treaty-based calculations.');return;}
    const effectiveRate=panStatus==='no'?Math.max(baseRate,0.20):baseRate;
    const sc=getSurcharge(surchargeKey);
    const tdsBase=amount*effectiveRate;
    const surchargeAmt=tdsBase*sc;
    const cessAmt=(tdsBase+surchargeAmt)*0.04;
    const totalTDS=tdsBase+surchargeAmt+cessAmt;
    const netPayable=amount-totalTDS;
    const noPanRate=Math.max(baseRate,0.20);
    const noPanTDS=amount*noPanRate;
    document.getElementById('r-gross').textContent=fmtI(amount);
    document.getElementById('r-rate').textContent=(effectiveRate*100).toFixed(1)+'%'+(panStatus==='no'?' (Section 206AA)':'');
    document.getElementById('r-tds').textContent=fmtI(totalTDS);
    document.getElementById('r-net').textContent=fmtI(netPayable);
    let html=`<div class="breakdown-row"><span class="breakdown-label">Gross Payment</span><span class="breakdown-value">${fmtI(amount)}</span></div>
    <div class="breakdown-row"><span class="breakdown-label">TDS Base (Sec. ${secId} @ ${(effectiveRate*100).toFixed(1)}%)</span><span class="breakdown-value">${fmtI(tdsBase)}</span></div>
    <div class="breakdown-row"><span class="breakdown-label">Surcharge ${sc>0?'('+Math.round(sc*100)+'%)':''}</span><span class="breakdown-value">${sc>0?fmtI(surchargeAmt):'Nil'}</span></div>
    <div class="breakdown-row"><span class="breakdown-label">Health &amp; Education Cess (4%)</span><span class="breakdown-value">${fmtI(cessAmt)}</span></div>
    <div class="breakdown-row"><span class="breakdown-label"><strong>Total TDS to Deduct</strong></span><span class="breakdown-value"><strong>${fmtI(totalTDS)}</strong></span></div>
    <div class="breakdown-row"><span class="breakdown-label"><strong>Net Payable to Deductee</strong></span><span class="breakdown-value"><strong>${fmtI(netPayable)}</strong></span></div>`;
    if(row.note)html+=`<div style="margin-top:10px;padding-top:10px;border-top:1px dashed #E5E5E0;font-size:12px;color:#888">&#8505; ${row.note}</div>`;
    document.getElementById('breakdownSection').innerHTML=html;
    const noPanCard=document.getElementById('noPanCard');
    if(panStatus==='yes'&&noPanRate>baseRate){document.getElementById('r-nopan').textContent=fmtI(noPanTDS);noPanCard.style.display='block';}
    else noPanCard.style.display='none';
    document.getElementById('resultSection').classList.add('visible');
    document.getElementById('resultSection').scrollIntoView({behavior:'smooth',block:'nearest'});
}

function resetCalc(){
    document.getElementById('calcSection').value='';
    document.getElementById('calcAmount').value='';
    document.getElementById('calcPayeeType').value='other';
    document.getElementById('calcSurcharge').value='individual_below50';
    panStatus='yes';
    document.querySelectorAll('.toggle-btn').forEach((b,i)=>b.classList.toggle('active',i===0));
    document.getElementById('resultSection').classList.remove('visible');
    document.getElementById('noPanCard').style.display='none';
}

const FAQS=[
    {q:"What is the TDS rate on salary under Section 192 for FY 2025\u201326?",a:"Under Section 192, TDS on salary is deducted as per the applicable income tax slab rates for FY 2025\u201326 under the new tax regime. The employer calculates estimated annual salary, applies the applicable slab (0%, 5%, 10%, 15%, 20%, 25%, or 30%), and deducts TDS monthly. No flat rate applies; the deduction depends on total taxable salary and exemptions claimed by the employee."},
    {q:"What happens if the payee does not provide PAN for TDS deduction?",a:"Under Section 206AA, if the payee fails to furnish a valid PAN, TDS must be deducted at 20% or the applicable rate, whichever is higher. This applies to all TDS sections. From FY 2024\u201325, Aadhaar-linked PAN is treated as valid. An inoperative (Aadhaar-unlinked) PAN is also treated as no PAN for this purpose, significantly increasing the tax burden on the payee."},
    {q:"What is the TDS rate for contractors and sub-contractors under Section 194C?",a:"Under Section 194C, TDS is deducted at 1% for payments to individuals or HUFs and 2% for payments to companies, firms, or co-operative societies. The threshold limit is \u20B930,000 per single contract or \u20B91,00,000 in aggregate during a financial year. Transport contractors with a valid PAN are exempt from TDS deduction under this section."},
    {q:"What is the TDS rate on rent under Section 194I?",a:"Under Section 194I, TDS on rent is deducted at 2% for use of plant, machinery, or equipment, and 10% for use of land, building, or furniture. The threshold limit is \u20B92,40,000 per financial year. Section 194IB at 5% applies separately when individual or HUF tenants pay monthly rent exceeding \u20B950,000."},
    {q:"What is the penalty for not deducting TDS or late TDS deposit?",a:"Interest under Section 201(1A) is charged at 1% per month for late deduction and 1.5% per month for late deposit of TDS. A penalty equal to the TDS amount can be levied under Section 271C for failure to deduct. Expenses on which TDS was not deducted may also be disallowed under Section 40(a)(ia), increasing the deductor's taxable income."},
    {q:"What is the TDS rate on professional fees under Section 194J?",a:"Under Section 194J, TDS is deducted at 10% on fees for professional services (doctors, lawyers, CAs, engineers) and at 2% on fees for technical services, royalty payments, and call centre payments. The threshold limit is \u20B950,000 per year. Directors' fees under Section 194J attract 10% with no threshold limit applicable."},
    {q:"What is TDS on purchase of property under Section 194IA?",a:"Under Section 194IA, TDS is deducted at 1% of the sale consideration when a buyer purchases immovable property (other than agricultural land) valued at \u20B950 lakh or more. The buyer must deduct TDS and file Form 26QB within 30 days from the end of the month of deduction via the income tax portal."},
    {q:"What is the TDS rate on virtual digital assets (crypto) under Section 194S?",a:"Under Section 194S, TDS is deducted at 1% on transfer of virtual digital assets including cryptocurrency and NFTs. The threshold is \u20B950,000 per year for specified persons and \u20B910,000 for others. The provision was introduced from 1 July 2022 to bring VDA transactions under the income tax compliance framework."},
    {q:"Can I claim a refund of excess TDS deducted?",a:"Yes. If TDS deducted exceeds your actual tax liability, you can claim a refund by filing your Income Tax Return (ITR). The excess TDS reflects in Form 26AS and AIS. After ITR processing, the Income Tax Department issues a refund directly to your registered bank account. Refunds can be tracked on the income tax portal at incometax.gov.in."},
    {q:"What is the due date for TDS deposit and return filing?",a:"TDS must be deposited by the 7th of the following month (30th April for March deductions). TDS returns \u2014 Form 24Q for salary, 26Q for non-salary, 27Q for non-resident payments \u2014 are due quarterly: Q1 by 31 July, Q2 by 31 October, Q3 by 31 January, and Q4 by 31 May. Form 16 or 16A must be issued within 15 days of the TDS return due date."},
    {q:"What is the TDS rate on interest from banks under Section 194A?",a:"Under Section 194A, TDS is deducted at 10% on interest income from banks, post offices, and cooperative societies. The threshold is \u20B940,000 for individuals (\u20B950,000 for senior citizens aged 60 and above) per financial year per bank. Submit Form 15G (below 60) or Form 15H (senior citizens) to avoid TDS if income is below the taxable limit."},
    {q:"What is Form 26AS and how does it help with TDS verification?",a:"Form 26AS is the annual consolidated tax statement available on the income tax portal that shows all TDS deducted against your PAN during a financial year. It includes TDS from salary, bank interest, rent, professional fees, and property transactions along with advance tax and self-assessment tax payments. Always verify Form 26AS before filing your ITR to ensure all TDS credits are correctly reflected."},
    {q:"How is TDS on e-commerce transactions deducted under Section 194O?",a:"Under Section 194O, e-commerce operators must deduct TDS at 1% of the gross amount paid or credited to e-commerce participants at the time of credit or payment, whichever is earlier. The threshold is \u20B95,00,000 for resident individual or HUF participants per financial year. No threshold applies for companies or firms registered on the platform, making compliance mandatory for all e-commerce operators in India."}
];

function buildFAQ(){
    const list=document.getElementById('faqList');
    FAQS.forEach(faq=>{
        const item=document.createElement('div');
        item.className='faq-item';
        item.innerHTML=`<button class="faq-question" onclick="toggleFaq(this)"><span>${faq.q}</span><span class="faq-icon">+</span></button><div class="faq-answer"><div class="faq-answer-inner">${faq.a}</div></div>`;
        list.appendChild(item);
    });
}

function toggleFaq(btn){
    const item=btn.closest('.faq-item');
    const isOpen=item.classList.contains('open');
    document.querySelectorAll('.faq-item').forEach(i=>i.classList.remove('open'));
    if(!isOpen)item.classList.add('open');
}

const navLinks=document.querySelectorAll('.toc-nav a');
window.addEventListener('scroll',()=>{
    let current='';
    document.querySelectorAll('[id]').forEach(s=>{if(window.pageYOffset>=s.offsetTop-80)current=s.getAttribute('id');});
    navLinks.forEach(l=>l.classList.toggle('active',l.getAttribute('href')==='#'+current));
});

document.addEventListener('DOMContentLoaded',()=>{
    buildTable();
    buildFAQ();
    updateMeta();
    document.getElementById('calcAmount').addEventListener('keydown',e=>{if(e.key==='Enter')calculateTDS();});
});
</script>
@endsection
